// frontend/src/pages/Dashboard.jsx
import React from "react";
import { useAuth } from "../context/AuthContext";

export default function Dashboard() {
  const { user, logout } = useAuth(); // Usamos 'user' porque así está en tu AuthContext

  return (
    <div
      style={{
        padding: "40px",
        maxWidth: "1000px",
        margin: "0 auto",
        width: "100%",
      }}
    >
      <header
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: "40px",
          borderBottom: "1px solid var(--border)",
          paddingBottom: "20px",
        }}
      >
        <div>
          <h2 style={{ margin: 0 }}>Bienvenido, {user?.nombre} 👋</h2>
          <p style={{ color: "var(--text-muted)", margin: "5px 0 0 0" }}>
            Rol:{" "}
            <span style={{ color: "var(--primary)", fontWeight: "bold" }}>
              {user?.rol}
            </span>{" "}
            | Departamento: {user?.departamento}
          </p>
        </div>
        <button
          onClick={logout}
          style={{
            width: "auto",
            background: "transparent",
            border: "1px solid var(--error)",
            color: "var(--error)",
          }}
        >
          Cerrar Sesión
        </button>
      </header>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))",
          gap: "20px",
        }}
      >
        {/* Tarjeta de Resumen */}
        <div className="card">
          <h4 style={{ color: "var(--text-muted)", marginTop: 0 }}>
            Solicitudes Totales
          </h4>
          <h2 style={{ fontSize: "2.5rem", margin: "10px 0" }}>12</h2>
          <p style={{ color: "var(--success)", fontSize: "14px" }}>
            ↑ 2 nuevas esta semana
          </p>
        </div>

        {/* Tarjeta de Pendientes */}
        <div
          className="card"
          style={{ borderLeft: "4px solid var(--primary)" }}
        >
          <h4 style={{ color: "var(--text-muted)", marginTop: 0 }}>
            Pendientes de Aprobación
          </h4>
          <h2 style={{ fontSize: "2.5rem", margin: "10px 0" }}>3</h2>
          <button style={{ padding: "8px 15px", fontSize: "14px" }}>
            Revisar ahora
          </button>
        </div>
      </div>

      <section style={{ marginTop: "40px" }}>
        <h3 style={{ marginBottom: "20px" }}>Acciones Rápidas</h3>
        <div style={{ display: "flex", gap: "15px" }}>
          <button style={{ flex: 1 }}>➕ Nueva Solicitud</button>
          <button
            style={{
              flex: 1,
              background: "var(--bg-card)",
              border: "1px solid var(--border)",
            }}
          >
            📂 Ver Historial
          </button>
        </div>
      </section>
    </div>
  );
}
